function i(t,e=Date.now()){if(!t)return"—";const r=Date.parse(t);if(Number.isNaN(r))return"—";const f=Math.floor(Math.max(0,e-r)/1e3);if(f<60)return"just now";const a=Math.floor(f/60);if(a<60)return`${a}m ago`;const n=Math.floor(a/60);if(n<24)return`${n}h ago`;const o=Math.floor(n/24);if(o<30)return`${o}d ago`;const u=Math.floor(o/30);return o<365?`${u}mo ago`:`${Math.floor(o/365)}y ago`}function s(t,e){if(!t)return"—";const r=Date.parse(t);return Number.isNaN(r)?"—":new Date(r).toLocaleString(e)}export{s as f,i as r};
